import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { SignInForm } from '../components/Auth/SignInForm';
import { SignUpForm } from '../components/Auth/SignUpForm';
import { CheckInCodeInput } from '../components/Points/CheckInCodeInput';
import { supabase } from '../lib/supabase';
import { EventCard } from '../components/EventCard';
import { useEvents } from '../hooks/useEvents';

export function Home() {
  const { user } = useAuth();
  const [showSignUp, setShowSignUp] = useState(false);
  const [userName, setUserName] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const { events, loading: eventsLoading, error: eventsError } = useEvents();

  useEffect(() => {
    const fetchUserName = async () => {
      if (!user) {
        setLoading(false);
        return;
      }

      try {
        const { data: profile, error } = await supabase
          .from('user_profiles')
          .select('first_name, last_name')
          .eq('id', user.id)
          .single();

        if (error) {
          console.error('Error fetching user profile:', error);
          return;
        }

        if (profile) {
          setUserName(`${profile.first_name || ''} ${profile.last_name || ''}`.trim() || 'there');
        }
      } catch (err) {
        console.error('Error fetching user name:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchUserName();
  }, [user]);

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center">
      <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        {user ? (
          <div className="space-y-12">
            {/* Welcome Section */}
            <div className="bg-white rounded-2xl shadow-xl p-8 transform transition-all hover:scale-[1.02]">
              <div className="text-center">
                <h1 className="text-4xl font-bold text-gray-900 mb-4">
                  Welcome back, {userName || 'there'}! 👋
                </h1>
                <p className="text-xl text-gray-600 mb-8">
                  Ready to earn some points today?
                </p>
                <div className="flex justify-center space-x-4">
                  <a
                    href="/profile"
                    className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-lg text-white bg-indigo-600 hover:bg-indigo-700 transition-colors duration-200 shadow-md hover:shadow-lg"
                  >
                    View Profile
                  </a>
                  <a
                    href="/leaderboard"
                    className="inline-flex items-center px-6 py-3 border border-gray-300 text-base font-medium rounded-lg text-gray-700 bg-white hover:bg-gray-50 transition-colors duration-200 shadow-md hover:shadow-lg"
                  >
                    View Leaderboard
                  </a>
                </div>
              </div>
            </div>

            {/* Check-in Code Section */}
            <div className="max-w-2xl mx-auto">
              <CheckInCodeInput />
            </div>

            {/* Events Section */}
            <div className="mt-16">
              <h2 className="text-3xl font-bold text-gray-900 mb-8 text-center">
                Upcoming Events
              </h2>
              {eventsLoading ? (
                <div className="flex justify-center">
                  <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
                </div>
              ) : eventsError ? (
                <div className="text-center text-red-500 bg-red-50 p-4 rounded-lg">
                  Error loading events: {eventsError.message}
                </div>
              ) : events.length === 0 ? (
                <div className="bg-white rounded-2xl shadow-xl p-8 text-center">
                  <p className="text-xl text-gray-600">No events scheduled at this time.</p>
                  <p className="text-gray-500 mt-2">Check back soon for upcoming events!</p>
                </div>
              ) : (
                <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
                  {events
                    .slice()
                    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
                    .map(event => (
                      <EventCard
                        key={event.id}
                        event={event}
                        onCheckIn={() => {}}
                      />
                    ))}
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="max-w-2xl mx-auto">
            <div className="text-center mb-12">
              <h1 className="text-4xl font-bold text-gray-900 mb-4">
                Welcome to VSA
              </h1>
              <p className="text-xl text-gray-600">
                Sign in or create an account to start earning points and participating in events.
              </p>
            </div>
            <div className="bg-white rounded-2xl shadow-xl p-8">
              {showSignUp ? (
                <>
                  <SignUpForm />
                  <p className="mt-6 text-center text-gray-600">
                    Already have an account?{' '}
                    <button
                      onClick={() => setShowSignUp(false)}
                      className="text-indigo-600 hover:text-indigo-500 font-medium transition-colors duration-200"
                    >
                      Sign In
                    </button>
                  </p>
                </>
              ) : (
                <>
                  <SignInForm />
                  <p className="mt-6 text-center text-gray-600">
                    Don't have an account?{' '}
                    <button
                      onClick={() => setShowSignUp(true)}
                      className="text-indigo-600 hover:text-indigo-500 font-medium transition-colors duration-200"
                    >
                      Sign Up
                    </button>
                  </p>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
